4059 static Instruction *
4060 foldICmpUSubSatOrUAddSatWithConstant(CmpPredicate Pred, SaturatingInst *II,
4061                                      const APInt &C,
4062                                      InstCombiner::BuilderTy &Builder) {
4063   // This transform may end up producing more than one instruction for the
4064   // intrinsic, so limit it to one user of the intrinsic.
4065   if (!II->hasOneUse())
4066     return nullptr;
4067 
4068   // Let Y        = [add/sub]_sat(X, C) pred C2
4069   //     SatVal   = The saturating value for the operation
4070   //     WillWrap = Whether or not the operation will underflow / overflow
4071   // => Y = (WillWrap ? SatVal : (X binop C)) pred C2
4072   // => Y = WillWrap ? (SatVal pred C2) : ((X binop C) pred C2)
4073   //
4074   // When (SatVal pred C2) is true, then
4075   //    Y = WillWrap ? true : ((X binop C) pred C2)
4076   // => Y = WillWrap || ((X binop C) pred C2)
4077   // else
4078   //    Y =  WillWrap ? false : ((X binop C) pred C2)
4079   // => Y = !WillWrap ?  ((X binop C) pred C2) : false
4080   // => Y = !WillWrap && ((X binop C) pred C2)
4081   Value *Op0 = II->getOperand(0);
4082   Value *Op1 = II->getOperand(1);
4083 
4084   const APInt *COp1;
4085   // This transform only works when the intrinsic has an integral constant or
4086   // splat vector as the second operand.
4087   if (!match(Op1, m_APInt(COp1)))
4088     return nullptr;
4089 
4090   APInt SatVal;
4091   switch (II->getIntrinsicID()) {
4092   default:
4093     llvm_unreachable(
4094         "This function only works with usub_sat and uadd_sat for now!");
4095   case Intrinsic::uadd_sat:
4096     SatVal = APInt::getAllOnes(C.getBitWidth());
4097     break;
4098   case Intrinsic::usub_sat:
4099     SatVal = APInt::getZero(C.getBitWidth());
4100     break;
4101   }
4102 
4103   // Check (SatVal pred C2)
4104   bool SatValCheck = ICmpInst::compare(SatVal, C, Pred);
4105 
4106   // !WillWrap.
4107   ConstantRange C1 = ConstantRange::makeExactNoWrapRegion(
4108       II->getBinaryOp(), *COp1, II->getNoWrapKind());
4109 
4110   // WillWrap.
4111   if (SatValCheck)
4112     C1 = C1.inverse();
4113 
4114   ConstantRange C2 = ConstantRange::makeExactICmpRegion(Pred, C);
4115   if (II->getBinaryOp() == Instruction::Add)
4116     C2 = C2.sub(*COp1);
4117   else
4118     C2 = C2.add(*COp1);
4119 
4120   Instruction::BinaryOps CombiningOp =
4121       SatValCheck ? Instruction::BinaryOps::Or : Instruction::BinaryOps::And;
4122 
4123   std::optional<ConstantRange> Combination;
4124   if (CombiningOp == Instruction::BinaryOps::Or)
4125     Combination = C1.exactUnionWith(C2);
4126   else /* CombiningOp == Instruction::BinaryOps::And */
4127     Combination = C1.exactIntersectWith(C2);
4128 
4129   if (!Combination)
4130     return nullptr;
4131 
4132   CmpInst::Predicate EquivPred;
4133   APInt EquivInt;
4134   APInt EquivOffset;
4135 
4136   Combination->getEquivalentICmp(EquivPred, EquivInt, EquivOffset);
4137 
4138   return new ICmpInst(
4139       EquivPred,
4140       Builder.CreateAdd(Op0, ConstantInt::get(Op1->getType(), EquivOffset)),
4141       ConstantInt::get(Op1->getType(), EquivInt));
4142 }
