4144 static Instruction *
4145 foldICmpOfCmpIntrinsicWithConstant(CmpPredicate Pred, IntrinsicInst *I,
4146                                    const APInt &C,
4147                                    InstCombiner::BuilderTy &Builder) {
4148   std::optional<ICmpInst::Predicate> NewPredicate = std::nullopt;
4149   switch (Pred) {
4150   case ICmpInst::ICMP_EQ:
4151   case ICmpInst::ICMP_NE:
4152     if (C.isZero())
4153       NewPredicate = Pred;
4154     else if (C.isOne())
4155       NewPredicate =
4156           Pred == ICmpInst::ICMP_EQ ? ICmpInst::ICMP_UGT : ICmpInst::ICMP_ULE;
4157     else if (C.isAllOnes())
4158       NewPredicate =
4159           Pred == ICmpInst::ICMP_EQ ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_UGE;
4160     break;
4161 
4162   case ICmpInst::ICMP_SGT:
4163     if (C.isAllOnes())
4164       NewPredicate = ICmpInst::ICMP_UGE;
4165     else if (C.isZero())
4166       NewPredicate = ICmpInst::ICMP_UGT;
4167     break;
4168 
4169   case ICmpInst::ICMP_SLT:
4170     if (C.isZero())
4171       NewPredicate = ICmpInst::ICMP_ULT;
4172     else if (C.isOne())
4173       NewPredicate = ICmpInst::ICMP_ULE;
4174     break;
4175 
4176   case ICmpInst::ICMP_ULT:
4177     if (C.ugt(1))
4178       NewPredicate = ICmpInst::ICMP_UGE;
4179     break;
4180 
4181   case ICmpInst::ICMP_UGT:
4182     if (!C.isZero() && !C.isAllOnes())
4183       NewPredicate = ICmpInst::ICMP_ULT;
4184     break;
4185 
4186   default:
4187     break;
4188   }
4189 
4190   if (!NewPredicate)
4191     return nullptr;
4192 
4193   if (I->getIntrinsicID() == Intrinsic::scmp)
4194     NewPredicate = ICmpInst::getSignedPredicate(*NewPredicate);
4195   Value *LHS = I->getOperand(0);
4196   Value *RHS = I->getOperand(1);
4197   return new ICmpInst(*NewPredicate, LHS, RHS);
