3951     unsigned OneUses = IIOp0->hasOneUse() + IIOp1->hasOneUse();
3952     if (OneUses == 2 ||
3953         (OneUses == 1 && match(IIOp0->getOperand(2), m_ImmConstant()) &&
3954          match(IIOp1->getOperand(2), m_ImmConstant()))) {
3955       Value *SubAmt =
3956           Builder.CreateSub(IIOp0->getOperand(2), IIOp1->getOperand(2));
3957       Value *CombinedRotate = Builder.CreateIntrinsic(
3958           Op0->getType(), IIOp0->getIntrinsicID(),
3959           {IIOp0->getOperand(0), IIOp0->getOperand(0), SubAmt});
3960       return new ICmpInst(Pred, IIOp1->getOperand(0), CombinedRotate);
3961     }
3962   } break;
3963   default:
3964     break;
3965   }
3966 
