3970 /// Try to fold integer comparisons with a constant operand: icmp Pred X, C
3971 /// where X is some kind of instruction and C is AllowPoison.
3972 /// TODO: Move more folds which allow poison to this function.
3973 Instruction *
3974 InstCombinerImpl::foldICmpInstWithConstantAllowPoison(ICmpInst &Cmp,
3975                                                       const APInt &C) {
3976   const ICmpInst::Predicate Pred = Cmp.getPredicate();
3977   if (auto *II = dyn_cast<IntrinsicInst>(Cmp.getOperand(0))) {
3978     switch (II->getIntrinsicID()) {
3979     default:
3980       break;
3981     case Intrinsic::fshl:
3982     case Intrinsic::fshr:
3983       if (Cmp.isEquality() && II->getArgOperand(0) == II->getArgOperand(1)) {
3984         // (rot X, ?) == 0/-1 --> X == 0/-1
3985         if (C.isZero() || C.isAllOnes())
3986           return new ICmpInst(Pred, II->getArgOperand(0), Cmp.getOperand(1));
3987       }
3988       break;
3989     }
3990   }
3991 
3992   return nullptr;
3993 }
