3995 /// Fold an icmp with BinaryOp and constant operand: icmp Pred BO, C.
3996 Instruction *InstCombinerImpl::foldICmpBinOpWithConstant(ICmpInst &Cmp,
3997                                                          BinaryOperator *BO,
3998                                                          const APInt &C) {
3999   switch (BO->getOpcode()) {
4000   case Instruction::Xor:
4001     if (Instruction *I = foldICmpXorConstant(Cmp, BO, C))
4002       return I;
4003     break;
4004   case Instruction::And:
4005     if (Instruction *I = foldICmpAndConstant(Cmp, BO, C))
4006       return I;
4007     break;
4008   case Instruction::Or:
4009     if (Instruction *I = foldICmpOrConstant(Cmp, BO, C))
4010       return I;
4011     break;
4012   case Instruction::Mul:
4013     if (Instruction *I = foldICmpMulConstant(Cmp, BO, C))
4014       return I;
4015     break;
4016   case Instruction::Shl:
4017     if (Instruction *I = foldICmpShlConstant(Cmp, BO, C))
4018       return I;
4019     break;
4020   case Instruction::LShr:
4021   case Instruction::AShr:
4022     if (Instruction *I = foldICmpShrConstant(Cmp, BO, C))
4023       return I;
4024     break;
4025   case Instruction::SRem:
4026     if (Instruction *I = foldICmpSRemConstant(Cmp, BO, C))
4027       return I;
4028     break;
4029   case Instruction::UDiv:
4030     if (Instruction *I = foldICmpUDivConstant(Cmp, BO, C))
4031       return I;
4032     [[fallthrough]];
4033   case Instruction::SDiv:
4034     if (Instruction *I = foldICmpDivConstant(Cmp, BO, C))
4035       return I;
4036     break;
4037   case Instruction::Sub:
4038     if (Instruction *I = foldICmpSubConstant(Cmp, BO, C))
4039       return I;
4040     break;
4041   case Instruction::Add:
4042     if (Instruction *I = foldICmpAddConstant(Cmp, BO, C))
4043       return I;
4044     break;
4045   default:
4046     break;
4047   }
4048 
4049   // TODO: These folds could be refactored to be part of the above calls.
4050   if (Instruction *I = foldICmpBinOpEqualityWithConstant(Cmp, BO, C))
4051     return I;
4052 
4053   // Fall back to handling `icmp pred (select A ? C1 : C2) binop (select B ? C3
4054   // : C4), C5` pattern, by computing a truth table of the four constant
4055   // variants.
4056   return foldICmpBinOpWithConstantViaTruthTable(Cmp, BO, C);
4057 }
